                          }}>
                            {participants
                              .filter(p => {
                                if (!p.email || !p.email.trim()) return false;
                                if (!editorSearch.trim()) return true;
                                const searchLower = editorSearch.toLowerCase();
                                const name = (p.name?.trim() || '').toLowerCase();
                                const email = p.email.trim().toLowerCase();
